steps.script:
() => {
  var html = document.documentElement.innerHTML;
  return {
    title: document.title,
    url: location.href,
    hasSignupForm: !!document.getElementById('signup'),
    pintrkType: typeof window.pintrk,
    pintrkQueued: (window.pintrk && window.pintrk.queue) ? window.pintrk.queue.length : null,
    clarityType: typeof window.clarity,
    fbqType: typeof window.fbq,
    hasPinScript: html.indexOf('s.pinimg.com/ct/core.js') > -1,
    hasPinTagId: html.indexOf('2613296930742') > -1,
    hasClarityTag: html.indexOf('clarity.ms/tag/wdwgfvbixn') > -1,
    hasLeadFire: html.indexOf(String.fromCharCode(39)+'lead'+String.fromCharCode(39)) > -1
  };
}
